	int maxSum = root->val + maxSubtreeSum(root->left, L, R) + maxSubtreeSum(root->right, L, R);
	if (L <= root->val && R >= root->val) maxSum = max(maxSum, root->val);
	return maxSum;
}
};

#include <iostream>
using namespace std;
class TreeNode {
public:
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int val = 0, TreeNode* left = nullptr, TreeNode* right = nullptr) : val(val), left(left), right(right) {}
};

int main() {
    // Read from std::cin
    int n;
    cin >> n;
    TreeNode* nodes[10000];
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        nodes[i] = new TreeNode(val);
    }
    for (int i = 0; i < n; i++) {
        if (i > 0) {
            nodes[i - 1]->left = nodes[i];
            nodes[i - 1]->right = nodes[i + 1] ? nodes[i + 1] : nullptr;
        }
    }
    // Read the range
    int L, R;
    cin >> L >> R;
    // Print the result
    Solution s;
    cout << s.maxSubtreeSum(nodes[0], L, R) << endl;
    return 0;
}
